   console.print(f"{pad}├─{'─' * 50}─┤")
   if not comp.children:
       subtitle = str(_resolve(comp, surface, "subtitle", ""))
       if subtitle:
           console.print(f"{pad}│  {subtitle:&lt;49}│")
       console.print(f"{pad}└─{'─' * 50}─┘")


