def log_event(event: AGUIEvent):
   if event.type in (AGUIEventType.STATE_SNAPSHOT, AGUIEventType.STATE_DELTA):
       if event.type == AGUIEventType.STATE_DELTA:
           ops = event.data.get("delta", [])
